[{"id":"a50882990","type":12,"x":259,"y":132,"info":"","config":{"varPrefix":"itens","dataType":"jsonraw","method":"post","retrys":1,"url":"http://{{clientIpCliente}}:{{clientPortCliente}}/api/buscar-medicamentos","data":{},"testData":{},"numberFields":[],"dataRaw":"{"query":  "{{assistant_produto_amplo}}", "unidade_negocio_id": {{unidade_negocio}}}","headers":{},"testHeaders":{},"timeout":15000,"expectedContentType":0,"textPreProcessor":0,"textPreProcessorSeparator":"","textPostProcessorSeparator":"","textResponseVariable":"","nextElementId":"a70925f30"},"configured":true},{"id":"a70925f30","type":21,"x":362,"y":40,"info":"","config":{"code":"// Obter lista de produtos e metadados
const produtos = vars?.['itens_rawBody']?.produtos || [];
const metadados = vars?.['itens_rawBody']?.metadados || {};
const modoSelecao = metadados.modo_selecao || 'top_3_relevancia';

const productList = [];

// IMPORTANTE: No modo faixa_preco, processar TODOS os produtos disponíveis primeiro
// para depois selecionar os 3 com base no preço real
const limiteProcessamento = modoSelecao === 'faixa_preco' ? produtos.length : 5;

// Processar produtos e calcular preço final
for (let i = 0; i < Math.min(limiteProcessamento, produtos.length); i++) {
    const produto = produtos[i];

    // Validar se o produto existe e tem descrição
    if (!produto || !produto.descricao) {
        continue;
    }

    // Validar estoque
    const estoqueDisponivel = Number(produto.estoque_disponivel) || 0;
    if (estoqueDisponivel <= 0) {
        continue;
    }

    // Nome do produto
    let nomeCompleto = produto.descricao;

    // Código de barras
    const codigo = produto.codigo_barras || produto.codigo || '-';

    // Preços com validação robusta
    const precoVenda = Number(produto.precos?.preco_venda) || 0;
    const precoCheio = Number(produto.precos?.preco_sem_desconto) || null;
    const precoDesconto = Number(produto.precos?.preco_com_desconto) || null;

    let preco = '';
    let temOferta = false;
    let precoFinal = 0; // PREÇO EFETIVO PARA COMPARAÇÃO

    // Lógica de preços - PRIORIDADE: preco_com_desconto > preco_venda > preco_sem_desconto
    if (precoDesconto !== null && precoDesconto > 0) {
        // Tem desconto válido
        precoFinal = precoDesconto;

        if (precoCheio !== null && precoCheio > 0 && precoDesconto < precoCheio) {
            const economia = ((precoCheio - precoDesconto) / precoCheio * 100).toFixed(0);
            preco = `💸 De R$ ${precoCheio.toFixed(2)} por R$ ${precoDesconto.toFixed(2)} (${economia}% OFF)`;
            temOferta = true;
        } else {
            preco = `R$ ${precoDesconto.toFixed(2)}`;
            temOferta = true;
        }
    } else if (precoVenda > 0) {
        // Usa o preço de venda padrão
        precoFinal = precoVenda;
        preco = `R$ ${precoVenda.toFixed(2)}`;
    } else if (precoCheio !== null && precoCheio > 0) {
        // Fallback para preço cheio
        precoFinal = precoCheio;
        preco = `R$ ${precoCheio.toFixed(2)}`;
    } else {
        // Nenhum preço válido, ignora o produto
        console.log(`[FRONTEND] Produto ignorado (sem preço): ${produto.descricao}`);
        continue;
    }

    // Informações adicionais de oferta
    let infoOferta = '';
    if (produto.precos?.tem_oferta_ativa) {
        const tipoOferta = produto.precos?.tipo_oferta;
        if (tipoOferta === 'leve_pague') {
            infoOferta = `\n🎁 Leve ${produto.precos?.leve} Pague ${produto.precos?.pague}`;
        } else if (produto.precos?.nome_caderno_oferta) {
            infoOferta = `\n🏷️ Oferta: ${produto.precos.nome_caderno_oferta}`;
        }
    }

    // Adicionar à lista COM O PREÇO FINAL CALCULADO
    productList.push({
        desc: nomeCompleto,
        price: preco,
        id: codigo,
        faixa: produto.faixa_preco || null,
        temOferta: temOferta,
        estoque: estoqueDisponivel,
        precoFinal: precoFinal,
        infoOferta: infoOferta
    });
}

// RE-CLASSIFICAR E SELECIONAR OS 3 MELHORES POR PREÇO (se modo for faixa_preco)
if (modoSelecao === 'faixa_preco' && productList.length > 0) {
    // Ordenar por preço final crescente
    productList.sort((a, b) => a.precoFinal - b.precoFinal);

    // Selecionar apenas os 3 primeiros (mais barato, médio, mais caro)
    const top3 = productList.slice(0, 3);

    // Aplicar badges baseado na posição
    if (top3.length >= 3) {
        top3[0].faixa = 'mais_barato';
        top3[0].desc = `💰 MAIS EM CONTA\n${top3[0].desc}`;

        top3[1].faixa = 'preco_medio';
        top3[1].desc = `⚖️ CUSTO-BENEFÍCIO\n${top3[1].desc}`;

        top3[2].faixa = 'mais_caro';
        top3[2].desc = `💎 PREMIUM\n${top3[2].desc}`;
    } else if (top3.length === 2) {
        top3[0].faixa = 'mais_barato';
        top3[0].desc = `💰 MAIS EM CONTA\n${top3[0].desc}`;

        top3[1].faixa = 'mais_caro';
        top3[1].desc = `💎 PREMIUM\n${top3[1].desc}`;
    }

    // Adicionar infoOferta
    top3.forEach(p => {
        if (p.infoOferta) {
            p.desc += p.infoOferta;
        }
    });

    // Substituir productList pelos 3 selecionados
    productList.length = 0;
    productList.push(...top3);

} else if (modoSelecao !== 'faixa_preco') {
    // Para outros modos, apenas adicionar badges originais + infoOferta
    const badges = {
        'mais_barato': '💰 MAIS EM CONTA',
        'preco_medio': '⚖️ CUSTO-BENEFÍCIO',
        'mais_caro': '💎 PREMIUM'
    };

    productList.forEach(p => {
        if (p.faixa && badges[p.faixa]) {
            p.desc = `${badges[p.faixa]}\n${p.desc}`;
        }
        if (p.infoOferta) {
            p.desc += p.infoOferta;
        }
    });
}

// Definir variáveis globais
vars['listaProdutos'] = productList;
vars['listaProdutosQuantidade'] = productList.length;
vars['modoSelecao'] = modoSelecao;
vars['currentMessageIndex'] = 0;
vars['listaFinal'] = [];
vars['index'] = 0;

// Log de resultado detalhado
console.log(`[FRONTEND] ${productList.length} produtos processados com sucesso`);
if (productList.length > 0) {
    console.log('[FRONTEND] Produtos selecionados:');
    productList.forEach((p, idx) => {
        console.log(`  ${idx + 1}. ${p.desc.split('\n').pop()} - R$ ${p.precoFinal.toFixed(2)} (${p.faixa || 'sem classificação'})`);
    });
}

